const https = require('https');
const crypto = require('crypto');
const fs = require('fs');

// Read service account
const sa = JSON.parse(fs.readFileSync('/c/Users/hara/.claude/credentials/google-service-account.json', 'utf8'));

// Create JWT
function base64url(str) {
  return Buffer.from(str).toString('base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');
}

const now = Math.floor(Date.now() / 1000);
const header = base64url(JSON.stringify({alg: 'RS256', typ: 'JWT'}));
const payload = base64url(JSON.stringify({
  iss: sa.client_email,
  scope: 'https://www.googleapis.com/auth/spreadsheets.readonly',
  aud: 'https://oauth2.googleapis.com/token',
  exp: now + 3600,
  iat: now
}));

const sign = crypto.createSign('RSA-SHA256');
sign.update(header + '.' + payload);
const sig = sign.sign(sa.private_key, 'base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');
const jwt = header + '.' + payload + '.' + sig;

// Get token
const tokenData = 'grant_type=urn%3Aietf%3Aparams%3Aoauth%3Agrant-type%3Ajwt-bearer&assertion=' + jwt;
const req = https.request({
  hostname: 'oauth2.googleapis.com',
  path: '/token',
  method: 'POST',
  headers: {'Content-Type': 'application/x-www-form-urlencoded'}
}, res => {
  let data = '';
