node << 'SCRIPT'
const https = require('https');
const crypto = require('crypto');
const fs = require('fs');

const sa = JSON.parse(fs.readFileSync('C:/Users/hara/.claude/mcp-servers/ga4-mcp/credentials.json', 'utf8'));
const PROPERTY_ID = '452176286';

async function getGA4Token() {
  const now = Math.floor(Date.now() / 1000);
  const header = Buffer.from(JSON.stringify({alg: 'RS256', typ: 'JWT'})).toString('base64url');
  const payload = Buffer.from(JSON.stringify({
    iss: sa.client_email,
    scope: 'https://www.googleapis.com/auth/analytics.readonly',
    aud: 'https://oauth2.googleapis.com/token',
    exp: now + 3600,
    iat: now
  })).toString('base64url');
  const sign = crypto.createSign('RSA-SHA256');
  sign.update(header + '.' + payload);
  const sig = sign.sign(sa.private_key).toString('base64url');
  const jwt = header + '.' + payload + '.' + sig;

  const tokenData = 'grant_type=urn%3Aietf%3Aparams%3Aoauth%3Agrant-type%3Ajwt-bearer&assertion=' + jwt;

  return new Promise((resolve, reject) => {
    const req = https.request({
      hostname: 'oauth2.googleapis.com',
      path: '/token',
      method: 'POST',
      headers: {'Content-Type': 'application/x-www-form-urlencoded', 'Content-Length': Buffer.byteLength(tokenData)}
    }, res => {
      let data = '';
      res.on('data', d => data += d);
      res.on('end', () => {
        const t = JSON.parse(data);
        if (t.access_token) resolve(t.access_token);
        else reject(new Error('Token error: ' + JSON.stringify(t)));
      });
    });
    req.write(tokenData);
    req.end();
  });
}

async function ga4Report(token, body) {
  const bodyStr = JSON.stringify(body);
  return new Promise((resolve, reject) => {
    const req = https.request({
      hostname: 'analyticsdata.googleapis.com',
      path: `/v1beta/properties/${PROPERTY_ID}:runReport`,
      method: 'POST',
      headers: {
        'Authorization': 'Bearer ' + token,
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(bodyStr)
      }
    }, res => {
      let data = '';
      res.on('data', d => data += d);
      res.on('end', () => resolve(JSON.parse(data)));
    });
    req.write(bodyStr);
    req.end();
  });
}

async function main() {
  const token = await getGA4Token();
  fs.writeFileSync('C:/Users/hara/.claude/tmp_ga4token.txt', token);
  console.log('GA4_TOKEN_OK');

  // 1. Funnel - 7 days (3/27-4/2)
  console.log('\n=== GA4 ファネル（3/27〜4/2）===');
  const funnel = await ga4Report(token, {
    dateRanges: [{startDate: '2026-03-27', endDate: '2026-04-02'}],
    dimensions: [{name: 'eventName'}],
    metrics: [{name: 'eventCount'}, {name: 'sessions'}],
    dimensionFilter: {
      filter: {
        fieldName: 'eventName',
        inListFilter: {values: ['view_item', 'add_to_cart', 'begin_checkout', 'purchase', 'session_start']}
      }
    }
  });
  console.log('Funnel result:', JSON.stringify(funnel.rows || funnel.error || funnel, null, 2));
}
main().catch(e => console.log('ERR:', e.message));
