  SESSION_RECORDINGS_URL
} from "./constants.js";
import {
  type FiltersType,
  type SortOptionsType,
  SortOptionsEnum
} from "./types.js";
import { tryAsync } from "./utils.js";

export async function queryAnalyticsDashboardAsync(
  query: string,
  timezone: string,
): Promise<any> {
  return await tryAsync(ANALYTICS_DASHBOARD_URL, {
    method: 'POST',
    headers: {
