node << 'SCRIPT'
const fs = require('fs');
const https = require('https');
const settings = JSON.parse(fs.readFileSync('C:/Users/hara/.claude/settings.local.json', 'utf8'));
const tokenArg = settings.mcpServers.clarity.args.find(a => a.includes('clarity_api_token'));
const CLARITY_TOKEN = tokenArg.split('=').slice(1).join('=');

async function clarityQuery(query) {
  const body = JSON.stringify({query: query, timezone: 'Asia/Tokyo'});
  return new Promise((resolve, reject) => {
    const req = https.request({
      hostname: 'clarity.microsoft.com',
      path: '/mcp/dashboard/query',
      method: 'POST',
      headers: {
        'Authorization': 'Bearer ' + CLARITY_TOKEN,
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(body)
      }
    }, res => {
      let data = '';
      res.on('data', d => data += d);
      res.on('end', () => resolve(JSON.parse(data)));
    });
    req.on('error', reject);
    req.write(body);
    req.end();
  });
}

async function main() {
  // More detailed Clarity analysis
  const queries = [
    'Scroll depth percentage breakdown by URL for all pages last 7 days including bottom 5 pages',
    'Dead clicks breakdown by URL for the last 7 days',
    'Sessions count and scroll depth for purchase page and shuwan-glass page for the last 7 days',
    'Device type breakdown sessions count for the last 7 days',
    'Click count on purchase button or cart button for the last 7 days'
  ];

  for (const q of queries) {
    try {
      const result = await clarityQuery(q);
      console.log('\nQuery:', q);
      console.log('Result:', JSON.stringify(result, null, 2).slice(0, 1200));
    } catch(e) {
      console.log('ERR for', q, ':', e.message);
    }
  }
}
main().catch(e => console.log('ERR:', e.message));
